  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  output        = \"../src/generated/client\"\n  binaryTargets = [\"native\", \"debian-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id               String        @id @default(uuid())\n  email            String        @unique\n  password         String\n  products         Product[]\n  sales            Sale[]\n  receipts         Receipt[]\n  expenses         Expense[]\n  customers        Customer[]\n  debts            Debt[]\n  plan             String        @default(\"FREE\")\n  role             String        @default(\"ADMIN\")\n  name             String?\n  owner_id         String?\n  staff            User[]        @relation(\"UserStaff\")\n  owner            User?         @relation(\"UserStaff\", fields: [owner_id], references: [id])\n  cashier_sales    Sale[]        @relation(\"CashierSales\")\n  admin_reports    ShiftReport[] @relation(\"AdminReports\")\n  staff_reports    ShiftReport[] @relation(\"StaffReports\")\n  business_name    String?\n  business_address String?\n  business_phone   String?\n  business_logo    String?\n  receipt_footer   String?\n  daily_goal       Float         @default(0)\n  last_login_at    DateTime?\n  is_suspended     Boolean       @default(false)\n  suppliers        Supplier[]\n  debt_payments    DebtPayment[] @relation(\"CashierPayments\")\n  messages         Message[]\n  created_at       DateTime      @default(now())\n}\n\nmodel Customer {\n  id         String   @id @default(uuid())\n  user_id    String\n  user       User     @relation(fields: [user_id], references: [id])\n  name       String\n  email      String?\n  phone      String?\n  address    String?\n  sales      Sale[]\n  debts      Debt[]\n  created_at DateTime @default(now())\n}\n\nmodel Product {\n  id                  String     @id @default(uuid())\n  user_id             String\n  user                User       @relation(fields: [user_id], references: [id])\n  name                String\n  sku                 String?\n  quantity            Int        @default(0)\n  unit                String     @default(\"pcs\")\n  cost_price          Float      @default(0)\n  selling_price       Float      @default(0)\n  low_stock_threshold Int        @default(5)\n  supplier_id         String?\n  supplier            Supplier?  @relation(fields: [supplier_id], references: [id])\n  image_url           String?\n  sale_items          SaleItem[]\n  created_at          DateTime   @default(now())\n}\n\nmodel Sale {\n  id             String     @id @default(uuid())\n  user_id        String\n  user           User       @relation(fields: [user_id], references: [id])\n  customer_id    String?\n  customer       Customer?  @relation(fields: [customer_id], references: [id])\n  total_amount   Float      @default(0)\n  payment_status String     @default(\"PAID\") // PAID, UNPAID, PARTIAL\n  cashier_id     String?\n  cashier        User?      @relation(\"CashierSales\", fields: [cashier_id], references: [id])\n  items          SaleItem[]\n  receipt        Receipt?\n  debt           Debt?\n  created_at     DateTime   @default(now())\n}\n\nmodel SaleItem {\n  id         String  @id @default(uuid())\n  sale_id    String\n  sale       Sale    @relation(fields: [sale_id], references: [id])\n  product_id String\n  product    Product @relation(fields: [product_id], references: [id])\n  quantity   Int\n  price      Float\n  cost_price Float   @default(0)\n}\n\nmodel Receipt {\n  id         String   @id @default(uuid())\n  sale_id    String   @unique\n  sale       Sale     @relation(fields: [sale_id], references: [id])\n  user_id    String\n  user       User     @relation(fields: [user_id], references: [id])\n  created_at DateTime @default(now())\n}\n\nmodel Expense {\n  id          String   @id @default(uuid())\n  user_id     String\n  user        User     @relation(fields: [user_id], references: [id])\n  description String\n  amount      Float\n  category    String   @default(\"General\")\n  date        DateTime @default(now())\n  created_at  DateTime @default(now())\n}\n\nmodel ShiftReport {\n  id                 String    @id @default(uuid())\n  admin_id           String\n  admin              User      @relation(\"AdminReports\", fields: [admin_id], references: [id])\n  cashier_id         String\n  cashier            User      @relation(\"StaffReports\", fields: [cashier_id], references: [id])\n  total_sales        Float     @default(0)\n  total_collections  Float     @default(0)\n  total_transactions Int       @default(0)\n  unpaid_sales_json  String? // Detailed list of new debts\n  collections_json   String? // Detailed list of debt collections\n  start_time         DateTime?\n  end_time           DateTime  @default(now())\n  created_at         DateTime  @default(now())\n}\n\nmodel Supplier {\n  id             String    @id @default(uuid())\n  user_id        String\n  user           User      @relation(fields: [user_id], references: [id])\n  name           String\n  contact_person String?\n  email          String?\n  phone          String?\n  address        String?\n  products       Product[]\n  created_at     DateTime  @default(now())\n}\n\nmodel Debt {\n  id               String        @id @default(uuid())\n  user_id          String\n  user             User          @relation(fields: [user_id], references: [id])\n  customer_id      String?\n  customer         Customer?     @relation(fields: [customer_id], references: [id])\n  customer_name    String? // Fallback for manual entry\n  amount           Float\n  remaining_amount Float\n  due_date         DateTime?\n  status           String        @default(\"PENDING\") // PENDING, PAID, PARTIAL\n  notes            String?\n  sale_id          String?       @unique\n  sale             Sale?         @relation(fields: [sale_id], references: [id])\n  payments         DebtPayment[]\n  created_at       DateTime      @default(now())\n}\n\nmodel DebtPayment {\n  id             String   @id @default(uuid())\n  debt_id        String\n  debt           Debt     @relation(fields: [debt_id], references: [id])\n  amount         Float\n  payment_method String   @default(\"CASH\")\n  cashier_id     String?\n  cashier        User?    @relation(\"CashierPayments\", fields: [cashier_id], references: [id])\n  date           DateTime @default(now())\n  created_at     DateTime @default(now())\n}\n\nmodel Message {\n  id         String    @id @default(uuid())\n  user_id    String\n  user       User      @relation(fields: [user_id], references: [id])\n  content    String\n  status     String    @default(\"PENDING\") // PENDING, READ, RESOLVED\n  reply      String?\n  replied_at DateTime?\n  attachment String?\n  created_at DateTime  @default(now())\n}\n\nmodel Announcement {\n  id         String   @id @default(uuid())\n  title      String\n  content    String\n  type       String   @default(\"INFO\") // INFO, WARNING, MAINTENANCE\n  created_at DateTime @default(now())\n}\n",
